1	// claim-office.ts
2	
3	type Customer = {
4	  yearsWithMHPCO: number;
5	};
6	
7	type Item = {
8	  type: string;
9	};
10	
11	type Step = {
12	  op: string;
13	  items?: Item[];
14	};
15	
16	type ScenarioInput = {
17	  customer: Customer;
18	  steps: Step[];
19	};
20	
21	type ScenarioOutput = {
22	  results: unknown[];
23	};
24	
25	const PROCESSING_FEE = 5;
26	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
27	const COMPONENT_BLOCK_SIZE = 3;
28	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
29	
30	const BASE_PREMIUMS: Record<string, number> = {
31	  sword: 100,
32	  amulet: 60,
33	  staff: 80,
34	  potion: 40,
35	  rune: 25,
36	};
37	
38	const quotePremium = (items: Item[]): number => {
39	  const totalBasePremium =
40	    items.length === COMPONENT_BLOCK_SIZE
41	      ? COMPONENT_BLOCK_BASE_PREMIUM
42	      : items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
43	  const firstInsuranceSurcharge =
44	    totalBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
45	  return totalBasePremium + firstInsuranceSurcharge + PROCESSING_FEE;
46	};
47	
48	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
49	  const items = input.steps[0].items ?? [];
50	  return { results: [{ premium: quotePremium(items) }] };
51	};
